#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

//uv1 is rect. screen, center at (0;0)
vec2 uv1 = (vUv-0.5)*uAspect.xy;
float corr = uTexSize.xy*texsize_noise_hq.zw*2;


//uv2 is derived from uv1: Horizon, Tilt, Movement
//1. shape horizion for small planet look
vec2 uv2 = uv1;
uv2.y =   uv1.y - .2*(uv1.x*uv1.x + uv1.y*uv1.y);

//2. Tilt
mat2 tilt = mat2(q30,q31,-q31,q30);
uv2 = multiply(tilt,uv2);

//3. Coord transform
float y0 = q3 ; //Horizon rel. to  screen
float z0 = .5 ; //  fish eye
float z = 8/abs(uv2.y+ y0); //factor for perspective
vec2 rs1 = vec2 (uv2.x*z,(uv2.y-1*z0)*z);

//Rotate map into viewing direction
mat2 dir = mat2(q24,q25,-q25,q24);
rs1 =  multiply(dir,rs1);

//Now move !
rs1 = rs1 - vec2 (0,q1);

float yr = (uv2.y +y0);
float mask = clamp01(16*yr) ;

vec3 sky2 = texture(sampler_noise_hq,0.001*rs1*corr);

float gravel =  lum(texture(sampler_noise_mq,0.008*rs1*corr));
float lav_mask = (sky2 * q28*(gravel+.0));;

float lava = 0.2+abs(lav_mask-0);
lava = clamp01(0.5/(lava+.1)-0.5);
float rock = (lav_mask)/64;

vec3 lay1 = clamp01(vec3 (lava,lava*(lava-0.52)*2,(lava-.94)*8));
lay1 = mask * (lay1 + rock * vec3 (.8,1,1));

vec3 copy = + GetBlur2(vec2(vUvOriginal.x, vUvOriginal.y+.00));
ret = lay1 + 0*mix(copy,lum(copy),0.8)*.5* mask
+ q22/(.03+abs(yr))*vec3(.7,.3,.9);


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

screen3 = vec3 ((vUv-.5)*uAspect.xy,1);//wirkt wie zoom
neu = GetBlur1(vUv)/4;

  pq  = project (sxy, vec3 (q10,q11,q12));
  pq2 = project (sxz, vec3 (q10,q11,q12));
  mask1 = (pq.x>=0)* (pq.x <=width);
  mask2 = (pq2.x>=0)*(pq2.x <= depth);
  if (mask1) {neu = mix(neu,wall(pq),blend);}
  if (mask2) {neu = mix(neu,wall(pq2),blend);}

  pq  = project (-sxy, vec3 (q13,q14,q15));
  pq2 = project (sxz, vec3 (q13,q14,q15));
  mask1 = (pq.x>=0)* (pq.x <=width);
  mask2 = (pq2.x>=0)*(pq2.x <= depth);
  if (mask1) {neu = mix(neu,wall(pq),blend);}
  if (mask2) {neu = mix(neu,wall(pq2),blend);}

  pq  = project (sxy, vec3 (q16,q17,q18));
  pq2 = project (sxz, vec3 (q16,q17,q18));
  mask1 = (pq.x>=0)* (pq.x <=width) * (dist2 >=0);
  mask2 = (pq2.x>=0)*(pq2.x <= depth)* (dist2 >=0);
  if (mask1) {neu = wall(pq);}
  if (mask2) {neu = wall(pq2);}
  musr = (q29%2)/length(abs(fract(pq2/2)-.5))*mask2;
  musr += (q29%2)/length(abs(fract(pq/2)-.5))*mask1;

  pq  = project (-sxy, vec3 (q19,q20,q21));
  pq2 = project (sxz, vec3 (q19,q20,q21));
  mask1 = (pq.x>=0)* (pq.x <=width) * (dist2 <=0);
  mask2 = (pq2.x>=0)*(pq2.x <= depth)* (dist2 <=0);
  if (mask1) {neu = wall(pq);}
  if (mask2) {neu = wall(pq2);}
  musl = ((q29+1)%2)/length(abs(fract(pq2/2)-.5))*mask2;
  musl += ((q29+1)%2)/length(abs(fract(pq/2)-.5))*mask1;

ret = texture(sampler_main,vUv+neu/8)
+neu*(1+roam_cos)*clamp01(audioLowSmooth*.04/length(vUv-.5))/2
*(audioLowSmooth) + clamp01((musl*roam_sin+musr*roam_cos)/16)*audioMidSmooth;


  fragColor = ret;
}
